// ── Injection function ──────────────────────────────────────────────────────

function injectPreschoolFields(filePath, newFields) {
  const src = fs.readFileSync(filePath, 'utf8');
  // Find the unique pattern: end of preschool faq + closing of preschool section + kindergarten start
  const marker = /\n    \},\n    'kindergarten':/;
  const match = src.match(marker);
  if (!match) {
    throw new Error(`Could not find preschool-kindergarten boundary in ${filePath}`);
  }
  // Insert the new fields before the closing }, of the preschool section
  const insertPos = match.index;
  const updated = src.slice(0, insertPos) + '\n' + newFields + '\n    },\n    \'kindergarten\':' + src.slice(match.index + match[0].length);
  fs.writeFileSync(filePath, updated, 'utf8');
  console.log(`  Updated ${path.basename(path.dirname(filePath))}/${path.basename(filePath)}`);
}

